def min_pul(pul_degerleri, hedef_posta):
    sonsuz = float("inf")
    dp = [0] + [sonsuz] * hedef_posta
    for t in range(1, hedef_posta + 1):
        for c in pul_degerleri:
            if c <= t and dp[t - c] + 1 < dp[t]:
                dp[t] = dp[t - c] + 1
    return dp[hedef_posta] if dp[hedef_posta] != sonsuz else -1
